1140	static void set_bin_relocs(RzCore *r, RzBinObject *o, RzBinReloc *reloc, bool va, Sdb **db, char **sdb_module) {
1141		bool is_pe = true;
1142	
1143		if (is_pe && reloc->import && reloc->import->name && reloc->import->libname && rz_str_startswith(reloc->import->name, "Ordinal_")) {
1144			char *module = reloc->import->libname;
1145			rz_str_case(module, false);
1146	
1147			// strip trailing ".dll"
1148			size_t module_len = strlen(module);
1149			if (module_len > 4 && !strcmp(module + module_len - 4, ".dll")) {
1150				module[module_len - 4] = '\0';
1151			}
1152	
1153			const char *import = reloc->import->name + strlen("Ordinal_");
1154			if (import) {
1155				char *filename = NULL;
1156				int ordinal = atoi(import);
1157				if (!*sdb_module || strcmp(module, *sdb_module)) {
1158					sdb_free(*db);
1159					*db = NULL;
1160					free(*sdb_module);
1161					*sdb_module = rz_str_dup(module);
1162					/* always lowercase */
1163					filename = rz_str_newf("%s.sdb", module);
1164					rz_str_case(filename, false);
1165					if (rz_file_exists(filename)) {
1166						*db = sdb_new(NULL, filename, 0);
1167					} else {
1168						free(filename);
1169						char *formats_dir = rz_path_system(r->sys_path, RZ_SDB_FORMAT);
1170						if (!formats_dir) {
1171							return;
1172						}
1173						filename = rz_str_newf(RZ_JOIN_3_PATHS("%s", "dll", "%s.sdb"), formats_dir, module);
1174						free(formats_dir);
1175						if (rz_file_exists(filename)) {
1176							*db = sdb_new(NULL, filename, 0);
1177						}
1178					}
1179				}
1180				if (*db) {
1181					// ordinal-1 because we enumerate starting at 0
1182					char *symname = resolveModuleOrdinal(*db, module, ordinal - 1); // uses sdb_get
1183					if (symname) {
1184						free(reloc->import->name);
1185						if (r->bin->prefix) {
1186							reloc->import->name = rz_str_newf("%s.%s", r->bin->prefix, symname);
1187							RZ_FREE(symname);
1188						} else {
1189							reloc->import->name = symname;
1190						}
1191					}
1192				}
1193				free(filename);
1194			}
1195			rz_analysis_hint_set_size(r->analysis, reloc->vaddr, 4);
1196			rz_meta_set(r->analysis, RZ_META_TYPE_DATA, reloc->vaddr, 4, NULL);
1197		}
